{
  "query": "query GetWorkflowDefinitions($category: String) {
    workflowDefinitions(category: $category) {
      id
      name
      description
      version
      category
      isActive
      createdAt
      updatedAt
    }
  }",
  "variables": {
    "category": null
  }
}

{
  "query": "query GetWorkflowDefinition($id: ID!) {
    workflowDefinition(id: $id) {
      id
      name
      description
      version
      bpmnXml
      category
      isActive
      createdAt
      updatedAt
    }
  }",
  "variables": {
    "id": "{{workflow_definition_id}}"
  }
}

{
  "query": "query GetWorkflowDefinitionsByCategory($category: String) {
    workflowDefinitions(category: $category) {
      id
      name
      description
      version
      category
      isActive
    }
  }",
  "variables": {
    "category": "admission"
  }
}

{
  "query": "mutation StartWorkflow($definitionId: ID!, $patientId: ID!, $variables: [KeyValuePairInput]) {\n    startWorkflow(definitionId: $definitionId, patientId: $patientId, initialVariables: $variables) {\n      id\n      definitionId\n      patientId\n      status\n      variables\n      createdAt\n    }\n  }",
  "variables": {
    "definitionId": "{{workflow_definition_id}}",
    "patientId": "{{patient_id}}",
    "variables": [
      {
        "key": "patientName",
        "value": "John Doe"
      },
      {
        "key": "admissionType",
        "value": "emergency"
      },
      {
        "key": "priority",
        "value": "high"
      }
    ]
  }
}

{
  "query": "query GetWorkflowInstances($status: WorkflowStatus, $patientId: ID) {
    workflowInstances(status: $status, patientId: $patientId) {
      id
      definitionId
      patientId
      status
      variables
      createdAt
      updatedAt
    }
  }",
  "variables": {
    "status": null,
    "patientId": null
  }
}

{
  "query": "query GetWorkflowInstancesByPatient($patientId: ID) {
    workflowInstances(patientId: $patientId) {
      id
      definitionId
      status
      variables
      createdAt
    }
  }",
  "variables": {
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "mutation SignalWorkflow($instanceId: ID!, $signalName: String!, $variables: [KeyValuePairInput]) {\n    signalWorkflow(instanceId: $instanceId, signalName: $signalName, variables: $variables)\n  }",
  "variables": {
    "instanceId": "{{workflow_instance_id}}",
    "signalName": "patient_data_updated",
    "variables": [
      {
        "key": "updateType",
        "value": "medical_history"
      },
      {
        "key": "updatedBy",
        "value": "doctor-123"
      }
    ]
  }
}

{
  "query": "query GetTasksByAssignee($assignee: ID!, $status: TaskStatus) {
    tasks(assignee: $assignee, status: $status) {
      id
      name
      description
      status
      assigneeId
      workflowInstanceId
      formData
      dueDate
      createdAt
      updatedAt
    }
  }",
  "variables": {
    "assignee": "test-user-123",
    "status": null
  }
}

{
  "query": "query GetTask($id: ID!) {
    task(id: $id) {
      id
      name
      description
      status
      assigneeId
      workflowInstanceId
      formData
      dueDate
      createdAt
      updatedAt
    }
  }",
  "variables": {
    "id": "{{task_id}}"
  }
}

{
  "query": "mutation ClaimTask($taskId: ID!) {
    claimTask(taskId: $taskId) {
      id
      status
      assigneeId
      claimedAt
    }
  }",
  "variables": {
    "taskId": "{{task_id}}"
  }
}

{
  "query": "mutation CompleteTask($taskId: ID!, $outputVariables: [KeyValuePairInput]) {\n    completeTask(taskId: $taskId, outputVariables: $outputVariables) {\n      id\n      status\n      completedAt\n      outputVariables\n    }\n  }",
  "variables": {
    "taskId": "{{task_id}}",
    "outputVariables": [
      {
        "key": "reviewResult",
        "value": "approved"
      },
      {
        "key": "notes",
        "value": "Patient data verified and approved for admission"
      },
      {
        "key": "reviewedBy",
        "value": "Dr. Smith"
      }
    ]
  }
}

{
  "query": "mutation DelegateTask($taskId: ID!, $userId: ID!) {
    delegateTask(taskId: $taskId, userId: $userId) {
      id
      assigneeId
      delegatedAt
      delegatedBy
    }
  }",
  "variables": {
    "taskId": "{{task_id}}",
    "userId": "supervisor-456"
  }
}
